import sys

def main():
    input = sys.stdin.read
    data = input().split()
    N = int(data[0])
    S = data[1]
    A = [int(c) for c in S]

    total = 0
    for i in range(N):
        current = A[i]
        for j in range(i, N):
            if i == j:
                current = A[i]
            else:
                current = 1 - (current & A[j])
            total += current
    print(total)

if __name__ == "__main__":
    main()
